<?php require 'config/db.php'; $pdo = getDB(); $groups = $pdo->query('SELECT id, scope FROM admin_g ORDER BY scope, id')->fetchAll(); $scope_counters = []; foreach ($groups as $g) { if (!isset($scope_counters[$g['scope']])) $scope_counters[$g['scope']] = 1; $pdo->prepare('UPDATE admin_g SET order_num = ? WHERE id = ?')->execute([$scope_counters[$g['scope']], $g['id']]); $scope_counters[$g['scope']]++; } echo "Initialized order_num for all records.\n";
